import os
import time
import random
import threading
from flask import Flask, request, send_file, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'videos/'
app.config['MAX_CONTENT_LENGTH'] = 1024 * 1024 * 1024  # 1 GB file size limit

video_streams = {}

@app.route('/upload', methods=['POST'])
def upload_video():
    file = request.files['video']
    filename = secure_filename(file.filename)
    file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    return jsonify({'message': 'Video uploaded successfully', 'filename': filename})

@app.route('/watch/<filename>', methods=['GET'])
def watch_video(filename):
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if os.path.exists(file_path):
        stream_id = str(random.randint(1000, 9999))
        video_streams[stream_id] = {'file_path': file_path, 'position': 0, 'quality': 'default'}
        return jsonify({'stream_id': stream_id})
    else:
        return jsonify({'error': 'Video file not found'}), 404

@app.route('/stream/<stream_id>', methods=['GET'])
def stream_video(stream_id):
    if stream_id in video_streams:
        video_stream = video_streams[stream_id]
        file_path = video_stream['file_path']
        position = video_stream['position']
        quality = video_stream['quality']

        def generate_video():
            with open(file_path, 'rb') as f:
                f.seek(position)
                while True:
                    data = f.read(1024 * 1024)  # Read 1 MB at a time
                    if not data:
                        break
                    yield data
                    video_streams[stream_id]['position'] += len(data)
                    time.sleep(0.1)  # Simulate streaming delay

        return app.response_class(generate_video(), mimetype='video/mp4')
    else:
        return jsonify({'error': 'Invalid stream ID'}), 404

@app.route('/control/<stream_id>', methods=['POST'])
def control_video(stream_id):
    if stream_id in video_streams:
        video_stream = video_streams[stream_id]
        file_path = video_stream['file_path']
        action = request.form.get('action')

        if action == 'pause':
            return jsonify({'message': 'Video paused'})
        elif action == 'resume':
            return jsonify({'message': 'Video resumed'})
        elif action == 'seek':
            position = int(request.form.get('position'))
            if position >= 0 and position < os.path.getsize(file_path):
                video_streams[stream_id]['position'] = position
                return jsonify({'message': 'Video seeked to position', 'position': position})
            else:
                return jsonify({'error': 'Invalid seek position'}), 400
        elif action == 'change_quality':
            quality = request.form.get('quality')
            if quality in ['low', 'medium', 'high']:
                video_streams[stream_id]['quality'] = quality
                return jsonify({'message': 'Video quality changed to', 'quality': quality})
            else:
                return jsonify({'error': 'Invalid video quality'}), 400
        else:
            return jsonify({'error': 'Invalid action'}), 400
    else:
        return jsonify({'error': 'Invalid stream ID'}), 404

if __name__ == '__main__':
    app.run(debug=True)

from flask import Flask, request, send_file
from functools import wraps
from io import BytesIO
import threading
import time

app = Flask(__name__)

# In-memory storage for videos
videos = {}

# Decorator to handle connection errors
def handle_connection_errors(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception as e:
            print(f"Connection error: {e}")
            return "Connection error", 500
    return wrapper

# Route to upload a video
@app.route('/upload', methods=['POST'])
def upload_video():
    file = request.files['video']
    video_id = str(len(videos) + 1)
    videos[video_id] = {
        'file': file,
        'current_position': 0,
        'lock': threading.Lock()
    }
    return video_id

# Route to stream a video
@app.route('/stream/<video_id>/<int:start_byte>-<int:end_byte>', methods=['GET'])
@handle_connection_errors
def stream_video(video_id, start_byte, end_byte):
    with videos[video_id]['lock']:
        video = videos[video_id]['file']
        video.seek(start_byte)
        data = video.read(end_byte - start_byte + 1)
        videos[video_id]['current_position'] = end_byte + 1
        return send_file(
            BytesIO(data),
            mimetype='video/mp4',
            as_attachment=True,
            attachment_filename=f"{video_id}.mp4",
            conditional=True,
            last_modified=time.ctime(video.last_modified)
        )

# Route to handle video controls (pause, resume, seek)
@app.route('/control/<video_id>', methods=['POST'])
@handle_connection_errors
def control_video(video_id):
    action = request.form['action']
    with videos[video_id]['lock']:
        if action == 'pause':
            return "OK"
        elif action == 'resume':
            return "OK"
        elif action == 'seek':
            position = int(request.form['position'])
            videos[video_id]['current_position'] = position
            return "OK"
        else:
            return "Invalid action", 400

if __name__ == '__main__':
    app.run(debug=True)

import os
import io
import threading
import time
import random

class VideoStream:
    def __init__(self, file_path, chunk_size=1024*1024):
        self.file_path = file_path
        self.chunk_size = chunk_size
        self.file_size = os.path.getsize(file_path)
        self.lock = threading.Lock()
        self.current_position = 0

    def read_chunk(self, start, end):
        with open(self.file_path, 'rb') as f:
            f.seek(start)
            return f.read(end - start + 1)

    def get_video_chunk(self, start, end):
        self.lock.acquire()
        try:
            if start < self.current_position:
                self.current_position = 0
            if end > self.file_size - 1:
                end = self.file_size - 1
            chunk = self.read_chunk(start, end)
            self.current_position = end + 1
            return chunk
        finally:
            self.lock.release()

    def get_video_info(self):
        return {
            'file_size': self.file_size,
            'chunk_size': self.chunk_size
        }

class VideoServer:
    def __init__(self, video_files):
        self.video_streams = {os.path.basename(f): VideoStream(f) for f in video_files}

    def get_video_chunk(self, video_name, start, end):
        if video_name not in self.video_streams:
            return None
        return self.video_streams[video_name].get_video_chunk(start, end)

    def get_video_info(self, video_name):
        if video_name not in self.video_streams:
            return None
        return self.video_streams[video_name].get_video_info()

class VideoClientSession:
    def __init__(self, video_server, video_name):
        self.video_server = video_server
        self.video_name = video_name
        self.video_info = self.video_server.get_video_info(video_name)
        self.current_position = 0
        self.quality_level = 0

    def get_video_chunk(self, quality_level=None):
        if quality_level is None:
            quality_level = self.quality_level
        chunk_size = self.video_info['chunk_size'] // (2 ** quality_level)
        start = self.current_position
        end = start + chunk_size - 1
        chunk = self.video_server.get_video_chunk(self.video_name, start, end)
        if chunk:
            self.current_position = end + 1
            return chunk
        return None

    def set_quality_level(self, quality_level):
        self.quality_level = quality_level

    def get_video_info(self):
        return self.video_info

class VideoStreamingWebsite:
    def __init__(self, video_files):
        self.video_server = VideoServer(video_files)
        self.client_sessions = {}

    def start_session(self, video_name):
        session = VideoClientSession(self.video_server, video_name)
        self.client_sessions[id(session)] = session
        return session

    def get_video_chunk(self, session_id, quality_level=None):
        if session_id not in self.client_sessions:
            return None
        session = self.client_sessions[session_id]
        return session.get_video_chunk(quality_level)

    def set_quality_level(self, session_id, quality_level):
        if session_id not in self.client_sessions:
            return
        session = self.client_sessions[session_id]
        session.set_quality_level(quality_level)

    def get_video_info(self, session_id):
        if session_id not in self.client_sessions:
            return None
        session = self.client_sessions[session_id]
        return session.get_video_info()

# Example usage
video_files = ['video1.mp4', 'video2.mp4', 'video3.mp4']
website = VideoStreamingWebsite(video_files)

# Start a session for a user
session = website.start_session('video1.mp4')

# Get video information
video_info = session.get_video_info()
print(video_info)

# Get video chunks with different quality levels
