chunk2 = session.get_video_chunk(quality_level=1)
chunk3 = session.get_video_chunk(quality_level=2)

# Set the quality level
session.set_quality_level(1)

# Get another chunk with the new quality level
chunk4 = session.get_video_chunk()

import os
import time
import threading
import queue
import logging

from typing import Tuple, Dict, Union
from collections import deque

class VideoStreamingService:
    def __init__(self, video_dir: str, max_concurrent_streams: int = 10):
        self.video_dir = video_dir
        self.max_concurrent_streams = max_concurrent_streams
        self.video_metadata: Dict[str, Dict[str, Union[str, int]]] = {}
        self.video_queues: Dict[str, queue.Queue] = {}
        self.video_threads: Dict[str, threading.Thread] = {}
        self.logger = logging.getLogger(__name__)

    def load_video_metadata(self):
        for filename in os.listdir(self.video_dir):
            if filename.endswith(".mp4"):
                video_path = os.path.join(self.video_dir, filename)
                video_size = os.path.getsize(video_path)
                self.video_metadata[filename] = {
                    "filename": filename,
                    "size": video_size,
                    "available_resolutions": ["240p", "360p", "480p", "720p", "1080p"],
                }

    def start_video_stream(self, username: str, video_filename: str, resolution: str) -> Tuple[int, int]:
        if video_filename not in self.video_metadata:
            raise ValueError(f"Video '{video_filename}' not found.")

        if video_filename not in self.video_queues:
            self.video_queues[video_filename] = queue.Queue()
            self.video_threads[video_filename] = threading.Thread(
                target=self.stream_video, args=(video_filename,)
            )
            self.video_threads[video_filename].start()

        video_queue = self.video_queues[video_filename]
        video_metadata = self.video_metadata[video_filename]

        position = video_queue.qsize()
        video_queue.put((username, resolution))

        self.logger.info(
            f"Started video stream for user '{username}' watching '{video_filename}' at {resolution} resolution. Position in queue: {position}."
        )

        return position, video_metadata["size"]

    def stream_video(self, video_filename: str):
        video_queue = self.video_queues[video_filename]
        video_metadata = self.video_metadata[video_filename]

        while True:
            while video_queue.qsize() < self.max_concurrent_streams:
                username, resolution = video_queue.get()
                self.logger.info(
                    f"Streaming video '{video_filename}' at {resolution} resolution for user '{username}'."
                )
                time.sleep(video_metadata["size"] / (1024 * 1024))  # Simulating video streaming
                self.logger.info(
                    f"Finished streaming video '{video_filename}' for user '{username}'."
                )

    def pause_video(self, username: str, video_filename: str):
        if video_filename not in self.video_queues:
            raise ValueError(f"Video '{video_filename}' is not being streamed.")

        video_queue = self.video_queues[video_filename]
        for i, (user, _) in enumerate(video_queue.queue):
            if user == username:
                self.logger.info(f"Paused video '{video_filename}' for user '{username}'.")
                video_queue.queue.rotate(i - len(video_queue.queue))
                break
        else:
            raise ValueError(f"User '{username}' is not streaming video '{video_filename}'.")

    def resume_video(self, username: str, video_filename: str):
        if video_filename not in self.video_queues:
            raise ValueError(f"Video '{video_filename}' is not being streamed.")

        video_queue = self.video_queues[video_filename]
        for i, (user, _) in enumerate(video_queue.queue):
            if user == username:
                self.logger.info(f"Resumed video '{video_filename}' for user '{username}'.")
                video_queue.queue.rotate(-i)
                break
        else:
            raise ValueError(f"User '{username}' is not streaming video '{video_filename}'.")

    def seek_video(self, username: str, video_filename: str, position: int):
        if video_filename not in self.video_queues:
            raise ValueError(f"Video '{video_filename}' is not being streamed.")

        video_queue = self.video_queues[video_filename]
        for i, (user, _) in enumerate(video_queue.queue):
            if user == username:
                self.logger.info(
                    f"Seeked video '{video_filename}' to position {position} for user '{username}'."
                )
                video_queue.queue.rotate(position - i)
                break
        else:
            raise ValueError(f"User '{username}' is not streaming video '{video_filename}'.")

