        return jsonify({'error': 'Video not found.'}), 404

    video_path = videos[filename]['path']
    viewer_id = len(videos[filename]['viewers'])
    videos[filename]['viewers'].append({'id': viewer_id, 'position': 0, 'quality': 'default'})

    def stream_video():
        chunk_size = 1024 * 1024  # 1 MB
        with open(video_path, 'rb') as f:
            while True:
                chunk = f.read(chunk_size)
                if not chunk:
                    break
                yield chunk

    return send_file(stream_video(), mimetype='video/mp4', as_attachment=True, attachment_filename=filename)

