def control_video(filename, viewer_id):
    if filename not in videos or int(viewer_id) >= len(videos[filename]['viewers']):
        return jsonify({'error': 'Video or viewer not found.'}), 404

    viewer = videos[filename]['viewers'][int(viewer_id)]
    data = request.get_json()

    if 'position' in data:
        viewer['position'] = data['position']
    if 'quality' in data:
        viewer['quality'] = data['quality']

    return jsonify({'message': 'Video control updated.'})

