app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
        return jsonify({'message': 'File uploaded successfully'}), 200
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/video/<filename>', methods=['GET'])
def stream_video(filename):
    try:
        range_header = request.headers.get('Range', None)
        if not range_header:
            return send_file(os.path.join(app.config['UPLOAD_FOLDER'], filename))

        size = os.path.getsize(os.path.join(app.config['UPLOAD_FOLDER'], filename))
        byte1, byte2 = 0, None
        m = re.search('(\d+)-(\d*)', range_header)
        if m:
            byte1 = int(m.groups()[0])
            byte2 = int(m.groups()[1]) if m.groups()[1] else size - 1
        range_length = byte2 - byte1 + 1

        resp = send_file(
            os.path.join(app.config['UPLOAD_FOLDER'], filename),
            direct_passthrough=True,
            conditional=True,
            mimetype='video/mp4',
            as_attachment=True,
            attachment_filename=filename,
            start_byte=byte1,
            end_byte=byte2
        )

        resp.headers.add('Content-Range', 'bytes {0}-{1}/{2}'.format(byte1, byte2, size))
        resp.headers.add('Accept-Ranges', 'bytes')
        return resp
    except Exception as e:
        return jsonify({'error': str(e)}), 500

