import time

app = Flask(__name__)
api = Api(app)

UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'mp4', 'avi', 'mov'}

if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

class VideoStreaming(Resource):
    def get(self, filename):
        try:
            return send_file(os.path.join(UPLOAD_FOLDER, filename), conditional=True)
        except FileNotFoundError:
            return {'error': 'Video not found'}, 404

    def post(self):
        if 'file' not in request.files:
            return {'error': 'No file uploaded'}, 400

        file = request.files['file']
        if file.filename == '':
            return {'error': 'No file selected'}, 400

        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            file.save(os.path.join(UPLOAD_FOLDER, filename))
            return {'message': 'File uploaded successfully', 'filename': filename}
        else:
            return {'error': 'Invalid file type'}, 400

    def put(self, filename):
        try:
            start = int(request.headers.get('Range', '0').split('-')[0])
            end = int(request.headers.get('Range', '').split('-')[1])
            chunk_size = 1024 * 1024  # 1 MB
            video_path = os.path.join(UPLOAD_FOLDER, filename)
            file_size = os.path.getsize(video_path)

            with open(video_path, 'rb') as f:
                f.seek(start)
                data = f.read(end - start + 1)

            response = send_file(
                io.BytesIO(data),
                mimetype='video/mp4',
                as_attachment=True,
                attachment_filename=filename,
                conditional=True
            )
            response.headers.add('Content-Range', f'bytes {start}-{end}/{file_size}')
            return response
        except FileNotFoundError:
            return {'error': 'Video not found'}, 404

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

api.add_resource(VideoStreaming, '/videos', '/videos/<string:filename>')

if __name__ == '__main__':
    app.run(debug=True)

