# Define video objects
class Video:
    def __init__(self, title, url, size, resolution):
        self.title = title
        self.url = url
        self.size = size
        self.resolution = resolution

# Define user session
class UserSession:
    def __init__(self, user_id):
        self.user_id = user_id
        self.current_video = None
        self.current_position = 0
        self.quality = "720p"

# Define video streaming server
class VideoStreamingServer(BaseHTTPRequestHandler):
    videos = [
        Video("Big Buck Bunny", "https://example.com/videos/big_buck_bunny.mp4", 100_000_000, "1080p"),
        Video("Tears of Steel", "https://example.com/videos/tears_of_steel.mp4", 50_000_000, "720p"),
        Video("Sintel", "https://example.com/videos/sintel.mp4", 25_000_000, "480p")
    ]
    user_sessions = {}

    def do_GET(self):
        parsed_url = urlparse(self.path)
        params = parse_qs(parsed_url.query)

        if parsed_url.path == "/videos":
            self.list_videos()
        elif parsed_url.path == "/watch":
            self.handle_video_playback(params)
        else:
            self.send_response(404)
            self.end_headers()

    def list_videos(self):
        self.send_response(200)
        self.send_header("Content-Type", "application/json")
        self.end_headers()

        video_data = [
            {
                "title": video.title,
                "url": video.url,
                "size": video.size,
                "resolution": video.resolution
            }
            for video in self.videos
        ]
        self.wfile.write(bytes(str(video_data), "utf-8"))

    def handle_video_playback(self, params):
        user_id = params.get("user_id", [str(uuid.uuid4())])[0]
        video_id = params.get("video_id", [0])[0]
        action = params.get("action", ["play"])[0]
        quality = params.get("quality", ["720p"])[0]

        if user_id not in self.user_sessions:
            self.user_sessions[user_id] = UserSession(user_id)

        user_session = self.user_sessions[user_id]

        if action == "play":
            self.play_video(user_session, video_id, quality)
        elif action == "pause":
            self.pause_video(user_session)
        elif action == "resume":
            self.resume_video(user_session)
        elif action == "seek":
            position = params.get("position", [0])[0]
            self.seek_video(user_session, position)
        elif action == "quality":
            self.set_video_quality(user_session, quality)
        else:
            self.send_response(400)
            self.end_headers()
            return

        self.send_response(200)
        self.end_headers()

    def play_video(self, user_session, video_id, quality):
        video = next((v for v in self.videos if v.url.endswith(f"{video_id}.mp4")), None)
        if video:
            user_session.current_video = video
            user_session.current_position = 0
            user_session.quality = quality
            self.stream_video(user_session)

    def pause_video(self, user_session):
        if user_session.current_video:
            user_session.current_position = self.get_current_position(user_session)

    def resume_video(self, user_session):
        if user_session.current_video:
            self.stream_video(user_session, user_session.current_position)

    def seek_video(self, user_session, position):
        if user_session.current_video:
            self.stream_video(user_session, position)

    def set_video_quality(self, user_session, quality):
        user_session.quality = quality

    def get_current_position(self, user_session):
        # Implement logic to get the current playback position
        return user_session.current_position

    def stream_video(self, user_session, start_position=0):
        if user_session.current_video:
            video = user_session.current_video
            headers = {
                "Range": f"bytes={start_position}-"
            }
            try:
                response = requests.get(video.url, headers=headers, stream=True)
                self.send_response(206)
                self.send_header("Content-Type", "video/mp4")
                self.send_header("Content-Length", str(video.size - start_position))
                self.end_headers()

                while True:
                    chunk = response.raw.read(1024)
                    if not chunk:
                        break
                    self.wfile.write(chunk)
                    user_session.current_position += len(chunk)
            except requests.exceptions.RequestException as e:
                self.send_response(500)
                self.end_headers()
                print(f"Error streaming video: {e}")

