# Video stream class
class VideoStream:
    def __init__(self, video_path):
        self.video_path = video_path
        self.stream = ffmpeg.input(video_path)
        self.current_position = 0
        self.is_paused = False
        self.queue = queue.Queue()
        self.thread = threading.Thread(target=self.stream_video)
        self.thread.start()

    def stream_video(self):
        while True:
            try:
                resolution, data = self.queue.get()
                ffmpeg.output(data, f'output_{resolution}.mp4').run()
            except queue.Empty:
                time.sleep(0.1)

    def play(self, resolution):
        self.queue.put((resolution, self.stream))

    def pause(self):
        self.is_paused = True

    def resume(self):
        self.is_paused = False

    def seek(self, position):
        self.current_position = position

    def rewind(self, seconds):
        self.current_position = max(0, self.current_position - seconds)

    def fast_forward(self, seconds):
        self.current_position += seconds

