import cv2
import numpy as np
from io import BytesIO
from PIL import Image

class VacUPlayer:
    def __init__(self, video_url, resolution=(1920, 1080), buffer_size=10):
        self.video_url = video_url
        self.resolution = resolution
        self.buffer_size = buffer_size
        self.buffer = queue.Queue(maxsize=buffer_size)
        self.player_thread = None
        self.is_playing = False
        self.current_frame = None
        self.current_time = 0
        self.total_duration = 0

    def start_player(self):
        self.player_thread = threading.Thread(target=self._player_loop)
        self.player_thread.start()
        self.is_playing = True

    def stop_player(self):
        self.is_playing = False
        self.player_thread.join()

    def seek(self, timestamp):
        self.current_time = timestamp
        self.buffer.queue.clear()

    def pause(self):
        self.is_playing = False

    def resume(self):
        self.is_playing = True

    def _player_loop(self):
        while self.is_playing:
            try:
                frame = self.buffer.get(timeout=1)
                self.current_frame = frame
                self.current_time += 1/30  # Assuming 30 FPS
                time.sleep(1/30)
            except queue.Empty:
                logging.error("Buffer underflow, trying to refill...")
                self._refill_buffer()

    def _refill_buffer(self):
        try:
            resp = requests.get(self.video_url)
            if resp.status_code == 200:
                video = BytesIO(resp.content)
                cap = cv2.VideoCapture(video)
                cap.set(cv2.CAP_PROP_POS_MSEC, self.current_time * 1000)
                self.total_duration = cap.get(cv2.CAP_PROP_FRAME_COUNT) / cap.get(cv2.CAP_PROP_FPS)

                while self.buffer.qsize() < self.buffer_size and self.is_playing:
                    ret, frame = cap.read()
                    if not ret:
                        break
                    frame = cv2.resize(frame, self.resolution)
                    self.buffer.put(frame)

                cap.release()
            else:
                logging.error(f"Error fetching video: {resp.status_code}")
        except Exception as e:
            logging.error(f"Error refilling buffer: {e}")

